pub struct ByteRef {
    id_addr: *mut u8,
    id_len: usize,
}
impl ByteRef {
    pub fn new(id: &mut [u8; 64]) -> Self {
        ByteRef {
            id_addr: id.as_mut_ptr() as _,
            id_len: id.len() as _,
        }
    }
}

poc_main_rs:
pub struct ByteRef {
    id_addr: *mut u8,
    id_len: usize,
}
impl ByteRef {
    pub fn new(id: &mut [u8; 64]) -> Self {
        ByteRef { id_addr: id.as_mut_ptr(), id_len: id.len() }
    }
    pub fn read(&self, idx: usize) -> u8 {
        unsafe { *self.id_addr.add(idx) }
    }
}
fn main() {
    let bref: ByteRef;
    {
        let mut id = [0u8; 64];
        bref = ByteRef::new(&mut id); // id will be dropped
    }
    let _ = bref.read(0); // UB: id is freed, id_addr is dangling
}

