pub fn extend_lifetime<'b, T>(r: &'b T) -> &'static T {
    unsafe { std::mem::transmute::<&'b T, &'static T>(r) }
}

poc_main_rs:
pub fn extend_lifetime<'b, T>(r: &'b T) -> &'static T {
    unsafe { std::mem::transmute::<&'b T, &'static T>(r) }
}
fn main() {
    let leaked: &'static u64;
    {
        let x = 42u64;
        leaked = extend_lifetime(&x); // x will be dropped at end of block
    }
    // x is now freed; leaked is dangling
    println!("{}", *leaked); // UB: use-after-free
}

