pub fn find_null(ptr: *const u8) -> usize {
    let mut i = 0;
    unsafe { while *ptr.add(i) != 0 { i += 1; } }
    i
}

poc_main_rs:
// MUF: assumes caller-supplied pointer is null-terminated
pub fn find_null(ptr: *const u8) -> usize {
    let mut i = 0;
    unsafe { while *ptr.add(i) != 0 { i += 1; } }
    i
}
fn main() {
    let data = b"hello"; // 5-byte allocation, no null terminator
    let len = find_null(data.as_ptr()); // UB: reads past 5-byte allocation
    println!("len={}", len);
}

