pub fn split_aliases<T>(x: &mut T) -> (&mut T, &mut T) {
    let p = x as *mut T;
    unsafe { (&mut *p, &mut *p) }
}

poc_main_rs:
pub fn split_aliases<T>(x: &mut T) -> (&mut T, &mut T) {
    let p = x as *mut T;
    unsafe { (&mut *p, &mut *p) } // UB: two &mut to same allocation
}
fn main() {
    let mut val = 42u64;
    let (a, b) = split_aliases(&mut val);
    *a = 1;
    *b = 2;
    println!("{} {}", a, b);
}

