    pub fn set_size(&mut self, size: usize) {
        self.in_use = size; // no bounds check!
    }
    pub fn active_bytes(&self) -> &[u8] {
        unsafe { std::slice::from_raw_parts(self.bytes.as_ptr(), self.in_use) }
    }
}
fn main() {
    let data = vec![0u8; 4];
    let mut buf = Buffer { bytes: data.into_boxed_slice(), in_use: 1 };
    buf.set_size(16); // violate: 16 > 4 (capacity)
    let _ = buf.active_bytes(); // UB: OOB read
}

