poc_main_rs:
pub fn write_ptr(ptr: *mut u64, val: u64) { unsafe { *ptr = val; } }
pub fn read_ptr(ptr: *const u64) -> u64 { unsafe { *ptr } }

struct SendPtr(usize); // store address as usize to bypass Send check on *mut
unsafe impl Send for SendPtr {}

fn main() {
    let mut data = 0u64;
    let addr = &mut data as *mut u64 as usize;
    let sp = SendPtr(addr);
    let h = std::thread::spawn(move || {
        write_ptr(sp.0 as *mut u64, 99); // concurrent write
    });
    let _ = read_ptr(addr as *const u64); // concurrent read — data race UB
    h.join().unwrap();
}

